<script lang="ts">
	import { onMount } from 'svelte';
	import { cubicOut } from 'svelte/easing';
	import { Tween } from 'svelte/motion';

	let { customClass = '' }: { customClass?: string } = $props();

	const POD_INITIAL_SCROLL_X = 107;

	let podXPosition = new Tween(POD_INITIAL_SCROLL_X, { duration: 1000, easing: cubicOut });
	let textOpacity = new Tween(0, { duration: 400, easing: cubicOut });
	let picture: HTMLElement;
	let hasStartedAnimation = false;

	onMount(() => {
		const handleScroll = () => {
			if (!picture || hasStartedAnimation) {
				return;
			}

			const threshold = window.innerHeight - 120;
			const pictureTop = picture.getBoundingClientRect().top;

			if (pictureTop <= threshold) {
				hasStartedAnimation = true;
				window.removeEventListener('scroll', handleScroll);

				const animation = podXPosition.set(325);
				animation.then(() => {
					textOpacity.set(1);
				});
			}
		};
		// Set the initial state
		handleScroll();
		window.addEventListener('scroll', handleScroll, { passive: true });

		return () => {
			window.removeEventListener('scroll', handleScroll);
		};
	});
</script>

